sys_script_include.script:
/**
 * @class ScriptEvaluator
 * @description Allows you to execute scripts from a GlideRecord field.
 * @since 19/02/2026
 * @date  19/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class ScriptEvaluator {


    // WARNING: Using this function might be considered as a violation of security policies.
    // Please make sure any use is based on conscious choice and careful assessment.
    /**
	 * Allows you to execute scripts from a GlideRecord field.
	 * 
	 * @param {String} scope sys_scope 
     * @param {String} sourceScript The script to be executed
     * @param {Object} params script paramters
     */
    executScript(scope, sourceScript, params) {
        const LIMIT = 1;
        var evaluatedValue = null;

        var gr = new GlideRecord('sys_script_include');
        gr.addQuery('sys_scope', scope);
        // // additional protection against accidental update
        gr.addQuery('sys_policy', 'read');
        gr.setLimit(LIMIT);
        gr.query();

        if (gr.next()) {

            var evaluator = new GlideScopedEvaluator();

            gr.setValue('script', sourceScript);
            gr.setValue('sys_scope', scope);

            evaluatedValue = evaluator.evaluateScript(gr, 'script', params);
            evaluatedValue = evaluator.getVariable('result');
        }

        return evaluatedValue;
    }

    /**
     * Allows you to execute scripts from a GlideRecord field.
	 * 
	 * @param {String} scope sys_scope 
     * @param {String} sourceScript The script to be executed
     * @param {String} param 1 - 7
     */
    runScript(scope, script, param1, param2, param3, param4, param5, param6, param7) {
        const LIMIT = 1;
        var evaluatedValue = null;

        var gr = new GlideRecord('sys_script_include');
        gr.addQuery('sys_scope', scope);
        // // additional protection against accidental update
        gr.addQuery('sys_policy', 'read');
        gr.setLimit(LIMIT);
        gr.query();

        if (gr.next()) {

            gr.setValue('script', script);
            gr.setValue('sys_scope', scope);

            var evaluator = new GlideScopedEvaluator();
            evaluator.putVariable('result', null);
            evaluator.putVariable('param1', param1);
            evaluator.putVariable('param2', param2);
            evaluator.putVariable('param3', param3);
            evaluator.putVariable('param4', param4);
            evaluator.putVariable('param5', param5);
            evaluator.putVariable('param6', param6);
            evaluator.putVariable('param7', param7);
            evaluator.evaluateScript(gr, 'script');
            evaluatedValue = evaluator.getVariable('result');
        }

        return evaluatedValue;
    }
}
